#include <stdio.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N;
        scanf("%d",&N);
        long long prev,cur;
        int sorted=1;
        if(N>0){
            scanf("%lld",&prev);
            for(int i=1;i<N;i++){
                scanf("%lld",&cur);
                if(cur<=prev) sorted=0;
                prev=cur;
            }
        }
        printf("%s\n", sorted?"YES":"NO");
    }
    return 0;
}

